const data = $input.first().json ?? {};

const intakeStau = Number(data.intake_stau ?? 0);
const intakeNullPayload = Number(data.intake_null_payload ?? 0);
const contactsUnscored = Number(data.contacts_unscored ?? 0);
const contactsNoEmbedding = Number(data.contacts_no_embedding ?? 0);
const dealsNoStage = Number(data.deals_no_stage ?? 0);

const dealsOpen = Number(data.deals_open ?? 0);
const contactsTotal = Number(data.contacts_total ?? 0);
const activities7d = Number(data.activities_7d ?? 0);

const issues = [];
if (intakeStau > 0) issues.push(`⚠️ Intake-Stau: ${intakeStau} Nachrichten >24h ohne Payload`);
if (intakeNullPayload > 0) issues.push(`❌ Intake-Bug: ${intakeNullPayload} neue Nachrichten ohne parsed_payload_json`);
if (contactsUnscored > 0) issues.push(`⚠️ ${contactsUnscored} Contacts ohne lead_score`);
if (contactsNoEmbedding > 0) issues.push(`⚠️ ${contactsNoEmbedding} Contacts ohne Embedding`);
if (dealsNoStage > 0) issues.push(`❌ ${dealsNoStage} Deals ohne Pipeline-Stage`);

const dateDe = new Date().toLocaleDateString('de-DE', {
  weekday: 'long',
  day: '2-digit',
  month: 'long',
  year: 'numeric',
});

let message;
if (issues.length === 0) {
  message = `✅ EIC Health Check OK\n${dateDe}\nDeals offen: ${dealsOpen} | Contacts: ${contactsTotal} | Activities 7d: ${activities7d}`;
} else {
  message = `🚨 EIC Health Check FEHLER\n${dateDe}\n\n${issues.join('\n')}\n\nDeals: ${dealsOpen} | Contacts: ${contactsTotal}`;
}

return [{ json: { message, ok: issues.length === 0 } }];
